import{_ as t,c as i,o,ag as s}from"./chunks/framework.DRADY2L-.js";const u=JSON.parse('{"title":"SkyZone SteadyView Operating Modes","description":"The Skyzone Steadyview video receiver (VRX) modules, like most modern VRX modules, contain two receivers that work simultaneously. This setup allows for vari...","frontmatter":{"description":"The Skyzone Steadyview video receiver (VRX) modules, like most modern VRX modules, contain two receivers that work simultaneously. This setup allows for vari...","gitAuthors":["mituritsyn","ikherty"]},"headers":[],"relativePath":"settings/skyzone.md","filePath":"en/settings/skyzone.md","lastUpdated":1774730062000}'),a={name:"settings/skyzone.md"};function r(n,e,l,d,h,m){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="skyzone-steadyview-operating-modes" tabindex="-1">SkyZone SteadyView Operating Modes <a class="header-anchor" href="#skyzone-steadyview-operating-modes" aria-label="Permalink to &quot;SkyZone SteadyView Operating Modes&quot;">​</a></h1><p>The Skyzone Steadyview video receiver (VRX) modules, like most modern VRX modules, contain two receivers that work simultaneously. This setup allows for various algorithms to improve signal reception and the final image quality. Starting from hardware version 3.2, Steadyview has four operating modes.</p><h3 id="operating-modes" tabindex="-1">Operating Modes: <a class="header-anchor" href="#operating-modes" aria-label="Permalink to &quot;Operating Modes:&quot;">​</a></h3><ul><li><strong>Div (Diversity)</strong>: The module works in traditional <a href="/intro/vrx">Diversity</a> mode. This means the goggles output the audio and video signal from the receiver with the highest signal strength (RSSI).</li></ul><p>The <strong>Mix</strong> modes aim to take images from both receivers simultaneously and merge them into one, filtering out interference.</p><ul><li><p><strong>Mix1</strong>: Provides basic image merging.</p></li><li><p><strong>Mix2</strong>: Improves synchronization stability. This refers to the sync pulse at the beginning of each PAL/NTSC frame. If the sync pulse is misread or lost due to interference, the resulting image will be distorted.</p></li><li><p><strong>Mix3</strong>: Enhances the sync signal based on Mix2, maximizing video stability and ensuring maximum compatibility with other display devices. Note that video brightness will be reduced in this mode.</p></li></ul><p>For these modes to work correctly, the latest firmware for both the module and the goggles is required.</p><hr><p><em>P.S. This is a loose translation of the <a href="https://skyzone.freshdesk.com/support/solutions/articles/151000020976-whats-the-mix1-mix2-mix3-div-mode" target="_blank" rel="noreferrer">official article</a> with author&#39;s additions.</em></p><h3 id="downloads-and-guides" tabindex="-1">Downloads and Guides: <a class="header-anchor" href="#downloads-and-guides" aria-label="Permalink to &quot;Downloads and Guides:&quot;">​</a></h3><ul><li><a href="https://www.skyzonefpv.com/pages/download" target="_blank" rel="noreferrer">Firmware and Instructions</a></li><li><a href="https://doggydog.blog/tag/skyzone/" target="_blank" rel="noreferrer">Further Skyzone Guides</a></li></ul>',11)])])}const p=t(a,[["render",r]]);export{u as __pageData,p as default};
